sql:
SELECT animal_name
FROM animals
WHERE animal_id = 1;

SELECT animal_id, AVG(average_weight) AS avg_weight
FROM physical_characteristics
GROUP BY animal_id;

SELECT status_name
FROM conservation_status
WHERE status_id = 1;

