sql:
SELECT COUNT(animal_id) AS endangered_animals_count
FROM animal_conservation
WHERE status_id = 0;

SELECT type_name
FROM animal_types
WHERE type_name = 'mammal';

SELECT type_name
FROM animal_types
WHERE type_id = 0;

SELECT behavior_name
FROM behaviors
WHERE behavior_id = 0;
